#!/usr/bin/env node
/**
 * strip.js
 * - Repairs almost-JSON with \xHH escapes and \' from JS-style dumps
 * - Then recursively keeps only "en" entries in language maps
 */

const fs = require("fs");

const LANG_KEY_RE = /^[a-z]{2}(?:-[A-Z]{2})?$/; // en, fr, de, zh-CN, zh-TW, kr, etc.

/** Convert \xHH to the corresponding character, unescape \', and remove stray backticks before },],, */
function repairJsonText(raw) {
  let txt = String(raw);

  // 1) Fix \xHH → actual character
  //    Example: "Juntando os peda\xe7os" → "Juntando os pedaços"
  txt = txt.replace(/\\x([0-9A-Fa-f]{2})/g, (_, hh) =>
    String.fromCharCode(parseInt(hh, 16))
  );

  // 2) Unescape \' (valid in JS strings, invalid in JSON) → '
  //    Example: "If you\'re" → "If you're"
  txt = txt.replace(/\\'/g, "'");

  // 3) Remove stray backticks that sometimes appear right after strings
  //    Example: ... "hr": "…"`\n  }  →  ... "hr": "…"\n  }
  txt = txt.replace(/`(?=\s*[}\],])/g, "");

  // (Optional) You can normalize line endings if needed
  // txt = txt.replace(/\r\n?/g, "\n");

  return txt;
}

// Returns a new structure with only EN where language maps are found
function stripExtraLanguages(node, keepLang = "en") {
  if (Array.isArray(node)) {
    return node.map((item) => stripExtraLanguages(item, keepLang));
  }
  if (node && typeof node === "object") {
    const keys = Object.keys(node);
    const langKeys = keys.filter((k) => LANG_KEY_RE.test(k) && typeof node[k] === "string");

    const isLangMap = langKeys.includes(keepLang) && langKeys.some((k) => k !== keepLang);

    if (isLangMap) {
      return { [keepLang]: node[keepLang] };
    }

    // Edge case: looks like a lang map but "en" is missing — keep the first string lang as "en"
    if (!langKeys.includes(keepLang) && langKeys.length >= 2 && langKeys.every((k) => typeof node[k] === "string")) {
      const first = langKeys[0];
      return { [keepLang]: node[first] };
    }

    const out = {};
    for (const k of keys) {
      out[k] = stripExtraLanguages(node[k], keepLang);
    }
    return out;
  }
  return node;
}

